-- =========================================================================
-- ESCO MIGRATION — PHASE 2: VEHICLES + CALENDAR
-- =========================================================================
--
-- Згенеровано tools/generate-esco-phase2.py
-- 11 авто з 71 seat-рядків Автопарку
-- 85 рейсів з Календаря
--
-- FK ланцюг: vehicles.id → calendar.vehicle_id (підзапит по auto_id).
-- Ідемпотентно: ON CONFLICT DO NOTHING по (tenant_id, auto_id|cal_id).
-- =========================================================================

BEGIN;

-- ── 1. Додаткова колонка на vehicles для розкладки місць ───────
ALTER TABLE public.vehicles ADD COLUMN IF NOT EXISTS seats_config jsonb;
COMMENT ON COLUMN public.vehicles.seats_config IS
    'Детальна розкладка місць: [{place, type, price_uah/chf/..., is_driver}, …]';

-- ── 2. UNIQUE індекси для ON CONFLICT ────────────────────────────
CREATE UNIQUE INDEX IF NOT EXISTS vehicles_tenant_auto_uidx ON public.vehicles (tenant_id, auto_id);
CREATE UNIQUE INDEX IF NOT EXISTS calendar_tenant_cal_uidx ON public.calendar (tenant_id, cal_id);

-- ── vehicles (11 авто) ───────────────────────────────

-- ── calendar (85 рейсів) ────────────────────────────

COMMIT;

NOTIFY pgrst, 'reload schema';